code = """import json
from datetime import datetime
import statistics
import calendar

# Data from previous queries
cases = var_call_nRFV9BuMwVFK7F8NPMH6hnYP
orderitems = var_call_EkLlgrBJHf2Cicam25ko6cAH

# Clean function
def clean_id(s):
    if s is None:
        return None
    return s.strip().lstrip('#')

order_ids = set(clean_id(r.get('Id') or r.get('id')) for r in orderitems)

# Build counts for months July 2020 through April 2021 (10 months)
start_year = 2020
start_month = 7
months = []
for i in range(10):
    m = start_month + i
    y = start_year + (m-1)//12
    mm = ((m-1)%12)+1
    months.append((y, mm))

month_labels = [calendar.month_name[m] for (y,m) in months]
counts = {label: 0 for label in month_labels}

for c in cases:
    oid = clean_id(c.get('orderitemid__c'))
    if oid in order_ids:
        cd = c.get('createddate')
        try:
            dt = datetime.strptime(cd, '%Y-%m-%dT%H:%M:%S.%f%z')
        except Exception:
            try:
                dt = datetime.strptime(cd, '%Y-%m-%dT%H:%M:%S%z')
            except Exception:
                continue
        label = calendar.month_name[dt.month]
        # Only count if within our 10-month window
        if label in counts and (dt.year, dt.month) in months:
            counts[label] += 1

# Prepare list of counts in the months order
counts_list = [counts[label] for label in month_labels]

final_answer = "None"
if any(counts_list):
    mean = statistics.mean(counts_list)
    stdev = statistics.pstdev(counts_list)  # population stdev
    max_count = max(counts_list)
    # Check for unique max
    if counts_list.count(max_count) == 1:
        if stdev == 0:
            # If stdev 0 but max greater than others impossible; keep None
            final_answer = "None"
        else:
            if max_count > mean + 2*stdev:
                idx = counts_list.index(max_count)
                final_answer = month_labels[idx]
            else:
                final_answer = "None"
    else:
        final_answer = "None"
else:
    final_answer = "None"

print("__RESULT__:")
print(json.dumps(final_answer))"""

